      // Render first 2 pages at 200 DPI via Ghostscript
      await execFileAsync(GS_EXE, [
        "-dNOPAUSE", "-dBATCH", "-dSAFER",
        "-sDEVICE=png16m",
        "-r200",
        "-dFirstPage=1", "-dLastPage=2",
        "-dMaxBitmap=500000000",
        `-sOutputFile=${path.join(tmpDir, "page-%d.png")}`,
        effectivePath,
      ], { timeout: 90_000 });

