async function inspectWithExtendScript(filePath: string): Promise<InspectionResult | null> {
  const tmpDir = await mkdtemp(path.join(tmpdir(), "popdam-jsx-"));
  const jsxPath = path.join(tmpDir, "inspect-rasters.jsx");
